-- Create "purchase_receipt_adjustments" table
CREATE TABLE "purchase_receipt_adjustments" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "adjustment_no" character varying NOT NULL,
  "reason" character varying NULL,
  "status" character varying NOT NULL DEFAULT 'DRAFT',
  "adjusted_at" timestamptz NOT NULL,
  "posted_at" timestamptz NULL,
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "business_record_id" bigint NULL,
  "purchase_receipt_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "purchase_receipt_adjustments_business_records_purchase_receipt_" FOREIGN KEY ("business_record_id") REFERENCES "business_records" ("id") ON UPDATE NO ACTION ON DELETE SET NULL,
  CONSTRAINT "purchase_receipt_adjustments_purchase_receipts_purchase_receipt" FOREIGN KEY ("purchase_receipt_id") REFERENCES "purchase_receipts" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create index "purchasereceiptadjustment_adjusted_at" to table: "purchase_receipt_adjustments"
CREATE INDEX "purchasereceiptadjustment_adjusted_at" ON "purchase_receipt_adjustments" ("adjusted_at");
-- Create index "purchasereceiptadjustment_adjustment_no" to table: "purchase_receipt_adjustments"
CREATE UNIQUE INDEX "purchasereceiptadjustment_adjustment_no" ON "purchase_receipt_adjustments" ("adjustment_no");
-- Create index "purchasereceiptadjustment_business_record_id" to table: "purchase_receipt_adjustments"
CREATE INDEX "purchasereceiptadjustment_business_record_id" ON "purchase_receipt_adjustments" ("business_record_id");
-- Create index "purchasereceiptadjustment_purchase_receipt_id" to table: "purchase_receipt_adjustments"
CREATE INDEX "purchasereceiptadjustment_purchase_receipt_id" ON "purchase_receipt_adjustments" ("purchase_receipt_id");
-- Create index "purchasereceiptadjustment_status" to table: "purchase_receipt_adjustments"
CREATE INDEX "purchasereceiptadjustment_status" ON "purchase_receipt_adjustments" ("status");
-- Create "purchase_receipt_adjustment_items" table
CREATE TABLE "purchase_receipt_adjustment_items" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "adjust_type" character varying NOT NULL,
  "quantity" numeric(20,6) NOT NULL,
  "source_line_no" character varying NULL,
  "correction_group" character varying NULL,
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "lot_id" bigint NULL,
  "material_id" bigint NOT NULL,
  "adjustment_id" bigint NOT NULL,
  "purchase_receipt_item_id" bigint NOT NULL,
  "unit_id" bigint NOT NULL,
  "warehouse_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "purchase_receipt_adjustment_items_inventory_lots_purchase_recei" FOREIGN KEY ("lot_id") REFERENCES "inventory_lots" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "purchase_receipt_adjustment_items_materials_purchase_receipt_ad" FOREIGN KEY ("material_id") REFERENCES "materials" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "purchase_receipt_adjustment_items_purchase_receipt_adjustments_" FOREIGN KEY ("adjustment_id") REFERENCES "purchase_receipt_adjustments" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "purchase_receipt_adjustment_items_purchase_receipt_items_purcha" FOREIGN KEY ("purchase_receipt_item_id") REFERENCES "purchase_receipt_items" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "purchase_receipt_adjustment_items_units_purchase_receipt_adjust" FOREIGN KEY ("unit_id") REFERENCES "units" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "purchase_receipt_adjustment_items_warehouses_purchase_receipt_a" FOREIGN KEY ("warehouse_id") REFERENCES "warehouses" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "purchase_receipt_adjustment_items_quantity_positive" CHECK (quantity > (0)::numeric)
);
-- Create index "purchasereceiptadjustmentitem_adjustment_id" to table: "purchase_receipt_adjustment_items"
CREATE INDEX "purchasereceiptadjustmentitem_adjustment_id" ON "purchase_receipt_adjustment_items" ("adjustment_id");
-- Create index "purchasereceiptadjustmentitem_adjustment_id_source_line_no" to table: "purchase_receipt_adjustment_items"
CREATE UNIQUE INDEX "purchasereceiptadjustmentitem_adjustment_id_source_line_no" ON "purchase_receipt_adjustment_items" ("adjustment_id", "source_line_no") WHERE ((source_line_no IS NOT NULL) AND ((source_line_no)::text <> ''::text));
-- Create index "purchasereceiptadjustmentitem_lot_id" to table: "purchase_receipt_adjustment_items"
CREATE INDEX "purchasereceiptadjustmentitem_lot_id" ON "purchase_receipt_adjustment_items" ("lot_id");
-- Create index "purchasereceiptadjustmentitem_material_id" to table: "purchase_receipt_adjustment_items"
CREATE INDEX "purchasereceiptadjustmentitem_material_id" ON "purchase_receipt_adjustment_items" ("material_id");
-- Create index "purchasereceiptadjustmentitem_purchase_receipt_item_id" to table: "purchase_receipt_adjustment_items"
CREATE INDEX "purchasereceiptadjustmentitem_purchase_receipt_item_id" ON "purchase_receipt_adjustment_items" ("purchase_receipt_item_id");
-- Create index "purchasereceiptadjustmentitem_warehouse_id" to table: "purchase_receipt_adjustment_items"
CREATE INDEX "purchasereceiptadjustmentitem_warehouse_id" ON "purchase_receipt_adjustment_items" ("warehouse_id");
